import { Button } from 'antd';
import { ArrowLeftOutlined } from '@ant-design/icons';

export const WebsiteRedesignContainer = ({ onBack }) => {
  return (
      <div>
        <div style={{ display: 'flex', alignItems: 'baseline', gap: '10px' }}>
            <Button shape="circle" onClick={onBack}>
                <ArrowLeftOutlined />
            </Button>
            <h2>Website Redesign</h2>
        </div>
        <p>This is the Website Redesign project page. Here you can find details about the project, its features, and how it was developed.</p>
        <iframe 
            title="Website Redesign Figma Prototype"
            style={{ 
                border: '1px solid rgb(255, 255, 255)', 
                width: '800px', 
                height: '450px' 
            }}
            src="https://embed.figma.com/proto/zQ2jjowNahrh5KpJA60l36/otto.de-Redesign?node-id=17-2&p=f&scaling=scale-down&content-scaling=fixed&page-id=3%3A3&embed-host=share" 
            allowfullscreen
        >
        </iframe>
      </div>
  );
}
